pub async fn get_list_from_query<'a,
    T1: GetDbType + FromSql<'a>>(query: &'a Result<Vec<Row>, Error>, file: &'static str, line: u32) -> Result<Vec<T1>, String> {
    match query {
        Err(err) => Err(handle_error(err, file, line).await),
        Ok(query) => {
            if query.is_empty() {
                return Ok(vec![]);
            }
            let db_val = query.first().unwrap();
            if db_val.columns().len() != 1 {
                let msg = "Unexpected DB response (columns)".to_string();
                create_alert_ex(file, line, &msg).await;
                return Err(msg);
            }
            if *db_val.columns()[0].type_() != T1::get_db_type() {
                let msg = "Unexpected DB response (column 1 type)".to_string();
                create_alert_ex(file, line, &msg).await;
                return Err(msg);
            }
            let mut result: Vec<T1> = Vec::with_capacity(query.len());
            for db_row in query {
                let db_val1: Result<T1, Error> = db_row.try_get(0);
                match db_val1 {
                    Err(err) => {
                        let msg = format!("{:?}", err);
                        create_alert_ex(file, line, &msg).await;
                        return Err(msg)
                    }
                    Ok(db_val1) => {
                        result.push(db_val1);
                    }
                }
            }
            Ok(result)
        }
    }
}

