pub trait GetDbType {
    fn get_db_type() -> Type;
}

impl GetDbType for i32 {
    fn get_db_type() -> Type {
        Type::INT4
    }
}

impl GetDbType for i64 {
    fn get_db_type() -> Type {
        Type::INT8
    }
}

impl GetDbType for Option<i64> {
    fn get_db_type() -> Type {
        Type::INT8
    }
}

impl GetDbType for &str {
    fn get_db_type() -> Type {
        Type::TEXT
    }
}

impl GetDbType for Uuid {
    fn get_db_type() -> Type {
        Type::UUID
    }
}

impl GetDbType for DateTime<Utc> {
    fn get_db_type() -> Type {
        Type::TIMESTAMPTZ
    }
}

impl GetDbType for Option<DateTime<Utc>> {
    fn get_db_type() -> Type {
        Type::TIMESTAMPTZ
    }
}

impl GetDbType for Vec<u8> {
    fn get_db_type() -> Type {
        Type::BYTEA
    }
}

impl GetDbType for bool {
    fn get_db_type() -> Type {
        Type::BOOL
    }
}

impl GetDbType for Vec<&str> {
    fn get_db_type() -> Type {
        Type::TEXT_ARRAY
    }
}

impl GetDbType for Vec<i32> {
    fn get_db_type() -> Type {
        Type::INT4_ARRAY
    }
}

impl GetDbType for Vec<i64> {
    fn get_db_type() -> Type {
        Type::INT8_ARRAY
    }
}

impl GetDbType for Vec<Decimal> {
    fn get_db_type() -> Type {
        Type::NUMERIC_ARRAY
    }
}

impl GetDbType for Vec<DateTime<Utc>> {
    fn get_db_type() -> Type {
        Type::TIMESTAMPTZ_ARRAY
    }
}

impl GetDbType for Vec<bool> {
    fn get_db_type() -> Type {
        Type::BOOL_ARRAY
    }
}
//Had to add because i had used VARCHAR instead of text fields in my DB
impl GetDbType for String {
    fn get_db_type() -> Type {
        Type::VARCHAR
    }
}
impl GetDbType for IpAddr {
    fn get_db_type() -> Type {
        Type::INET
    }
}

impl GetDbType for Decimal {
    fn get_db_type() -> Type {
        Type::NUMERIC
    }
}

impl GetDbType for Option<Decimal> {
    fn get_db_type() -> Type {
        Type::NUMERIC
    }
}

pub async fn handle_error(error: &Error, file: &'static str, line: u32) -> String {
    if error.is_closed() {
        let msg = format!("DB died during query: {:?}", error);
        create_alert_ex(file, line, &msg).await;
        return "DB down".to_string(); // This allows vgw-db error to be shown correctly to the frontend if connection died while query in progress.
    }
    if let Some(code) = error.code() {
        // V**** error codes can be explicitly handled, are application specific
        // and do not represent a system error.
        if code.code().starts_with("V") {
            return code.code().to_string();
        }
    }
    let msg = format!("DB Error: {:?}", error).replace("\\n", "\n");
    create_alert_ex(file, line, &msg).await;
    msg
}
